DROP TABLE IF EXISTS `clearance_sale_product`;
CREATE TABLE `clearance_sale_product`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `clearance_sale_id` bigint UNSIGNED NOT NULL,
  `product_id` bigint UNSIGNED NOT NULL,
  `discount_amount` decimal(10, 2) NOT NULL DEFAULT 0.00,
  `discount_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'flat',
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `clearance_sale_product_clearance_sale_id_product_id_unique`(`clearance_sale_id` ASC, `product_id` ASC) USING BTREE,
  INDEX `clearance_sale_product_product_id_foreign`(`product_id` ASC) USING BTREE,
  CONSTRAINT `clearance_sale_product_clearance_sale_id_foreign` FOREIGN KEY (`clearance_sale_id`) REFERENCES `clearance_sales` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `clearance_sale_product_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

