-- ----------------------------
-- Table structure for template_download_tokens
-- ----------------------------
DROP TABLE IF EXISTS `template_download_tokens`;
CREATE TABLE `template_download_tokens`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` bigint UNSIGNED NOT NULL,
  `template_id` bigint UNSIGNED NOT NULL,
  `token` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `expires_at` timestamp NOT NULL,
  `used_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `template_download_tokens_token_unique`(`token` ASC) USING BTREE,
  INDEX `template_download_tokens_user_id_foreign`(`user_id` ASC) USING BTREE,
  INDEX `template_download_tokens_template_id_foreign`(`template_id` ASC) USING BTREE,
  CONSTRAINT `template_download_tokens_template_id_foreign` FOREIGN KEY (`template_id`) REFERENCES `templates` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `template_download_tokens_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 30004 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

