-- ----------------------------
-- Table structure for templates
-- ----------------------------
DROP TABLE IF EXISTS `templates`;
CREATE TABLE `templates`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `tpl_code` varchar(12) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `price` decimal(10, 2) NOT NULL,
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `theme_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('active','draft','archived') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `templates_tpl_code_unique`(`tpl_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 30008 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of templates
-- ----------------------------
INSERT INTO `templates` VALUES (1, 'TPLCAFE1', 'Cafe Shop – Premium Culinary Theme', 'A beautifully designed template tailored for cafes, bistros, bakeries, and fine dining establishments. Clean, elegant, and interactive.', 79.00, 'templates/cafe_shop.zip', 'cafe_shop', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');
INSERT INTO `templates` VALUES (2, 'TPLELEC2', 'Electronic – Gadgets & Widescreen Store', 'Perfect theme for high-tech shops, smart devices, appliance outlets, and electronics cataloging. Optimized for wide grids.', 89.00, 'templates/electronic.zip', 'electronic', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');
INSERT INTO `templates` VALUES (3, 'TPLFASH3', 'Fashion & Style Boutique Theme', 'Elegant, chic aesthetic designed for apparel boutiques, clothing lines, and styling houses. Dynamic catalogs and full screens.', 99.00, 'templates/fashion.zip', 'fashion', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');
INSERT INTO `templates` VALUES (4, 'TPLGOLD4', 'Minimal Dark Gold – Luxury Theme', 'Deep dark palette accented with gold details. Ideal for jewelry, premium products, designer pieces, and luxury boutiques.', 69.00, 'templates/minimal_dark_gold.zip', 'minimal_dark_gold', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');
INSERT INTO `templates` VALUES (5, 'TPLMOBA5', 'eMarket – Premium Mobile Store', 'Full-featured mobile e-commerce experience with bottom tabs, home, wishlist, cart, variant selectors, and product detail screens. Responsive across phone & tablet.', 79.00, 'templates/smartphone_emarket.zip', 'smartphone_emarket', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');
INSERT INTO `templates` VALUES (6, 'TPLMOBB6', 'Foodie – Gourmet Delivery App', 'Immersive food delivery mobile template with flash sale banners, category browsing, cart calculations, order confirmations, and responsive bottom tabs.', 69.00, 'templates/smartphone_foodie.zip', 'smartphone_foodie', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');
INSERT INTO `templates` VALUES (7, 'TPLMOBC7', 'Luxe – Fashion Boutique App', 'Elegant editorial fashion mobile catalog with variant selectors, wishlist management, cart discounts, and smooth layout transitions.', 89.00, 'templates/smartphone_luxe.zip', 'smartphone_luxe', 'active', '2026-06-12 13:40:23', '2026-06-12 13:40:23');

-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `first_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `last_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `gender` enum('male','female') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `role_id` bigint UNSIGNED NULL DEFAULT NULL,
  `phone` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `city` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `country` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `state` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `is_online` tinyint(1) NOT NULL DEFAULT 0,
  `last_seen_at` timestamp NULL DEFAULT NULL,
  `email_verified_at` timestamp NULL DEFAULT NULL,
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `remember_token` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` bigint UNSIGNED NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `users_email_unique`(`email` ASC) USING BTREE,
  INDEX `users_role_id_foreign`(`role_id` ASC) USING BTREE,
  CONSTRAINT `users_role_id_foreign` FOREIGN KEY (`role_id`) REFERENCES `roles` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 60022 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

